async function sendExistingCrmEvents(trx, userCRMdetails, subStatus){
    let crmQueryList = [];
    const crmEventDetails = await getCRMeventDetails(trx, userCRMdetails.id);
    for(const eventD of crmEventDetails){
        await module.exports.sendCRMUserStatus(trx, userCRMdetails.opportunity_id, eventD.status, eventD.timestamp);
        crmQueryList.push(trx(`tradefinance.crm_event_details`).update({deleted_at: new Date()}).where(`crm_id`, userCRMdetails.id).andWhere(`status`, eventD.status));
    }
    if(crmQueryList.length > 0){
        await Promise.all(crmQueryList);
    }
    module.exports.sendCRMUserStatus(trx, userCRMdetails.opportunity_id, subStatus, new Date());
}

