async function _shuffleArray(array) {
      let n = array.length;
      var tmpArray = Array.from(array);
      while (n != 0) {
          let randInd = Math.floor(Math.random() * n);
          n--;
          let tmp = tmpArray[n];
          tmpArray[n] = tmpArray[randInd];
          tmpArray[randInd] = tmp;
      }
      return tmpArray.join("");
  }

