getDataForDatalakeSyncReport: async (trx, payload) => {
    let subqueries = payload.map(({ schema, table, column }) => {
      return trx.raw(
        `(SELECT CAST(?? AS text) FROM ?? WHERE ?? is NOT NULL ORDER BY ?? DESC LIMIT 1) AS ??`,
        [column, `${schema}.${table}`, column, column, `${schema}_${table}_${column}`]
      );
    });

    subqueries = trx.select(subqueries);
    const [resultRow] = await subqueries;

    const finalOutput = payload.map(({ schema, table, column }) => ({
      schema,
      table,
      column,
      value: resultRow[`${schema}_${table}_${column}`]
    }));

    return finalOutput;
  }

