upsert: async (db, tableName, object, constraint) => {
    const insert = db(tableName).insert(object);
    const update = db.queryBuilder().update(object);

    const upsertQuery = db.raw(`? ON CONFLICT ${constraint} DO ? returning *`, [insert, update]);

    const upsertRes = await upsertQuery;

    return upsertRes.rows;
  },

