    companyName = companyName.toLowerCase();
    if (country && country !== "")
      country = country.toLowerCase();
    return await db(`tradefinance.panjiva_organisations`)
    .select(`organisation_name AS company_name`, `country`)
    .from(`tradefinance.panjiva_organisations`)
    .whereRaw(`LOWER(organisation_name::text) like '%${companyName}%'`)
    .andWhere(qb => {
      if (country && country !== "")
        qb.whereRaw(`LOWER(country::text) = '${country}'`)
    });
  };

